<script setup lang="ts">import{onMounted,reactive,ref}from'vue';import{api}from'../api';const p=ref<any>({positions:[]});const orders=ref<any[]>([]);const form=reactive({symbol:'600000',side:'BUY',quantity:100,price:10});const msg=ref('');async function load(){p.value=await api.get('/portfolio');orders.value=await api.get('/portfolio/orders')}async function create(){const id=await api.post('/portfolio/orders',form);msg.value='已创建待确认委托 #'+id;await load()}async function confirm(id:number){await api.post(`/portfolio/orders/${id}/confirm`);await load()}onMounted(load);
</script>
<template><h1 class="page-title">持仓与人工确认委托</h1><div class="grid4"><div class="card metric"><label>总资产</label><strong>{{p.totalAsset}}</strong></div><div class="card metric"><label>现金</label><strong>{{p.cash}}</strong></div><div class="card metric"><label>市值</label><strong>{{p.marketValue}}</strong></div><div class="card metric"><label>持仓数</label><strong>{{p.positions?.length}}</strong></div></div><div class="section-grid"><div class="card"><h3>委托录入</h3><div class="form-row"><input v-model="form.symbol" maxlength="6"><select v-model="form.side"><option>BUY</option><option>SELL</option></select><input v-model.number="form.quantity" type="number" step="100"><input v-model.number="form.price" type="number" step="0.01"><button class="btn" @click="create">生成待确认委托</button></div><p class="success">{{msg}}</p><p class="muted">确认后仍需在券商客户端核对并手工提交，本软件不会保存券商密码。</p></div><div class="card"><h3>风险限制</h3><p class="muted">数量必须为100股整数倍</p><p class="muted">单股不超过总资金20%</p><p class="muted">最多同时持有5只</p></div></div><div class="card" style="margin-top:12px"><h3>最近委托</h3><table class="table"><thead><tr><th>ID</th><th>代码</th><th>方向</th><th>数量</th><th>限价</th><th>状态</th><th>操作</th></tr></thead><tbody><tr v-for="o in orders" :key="o.id"><td>{{o.id}}</td><td>{{o.symbol}}</td><td>{{o.side}}</td><td>{{o.quantity}}</td><td>{{o.limit_price}}</td><td>{{o.status}}</td><td><button v-if="o.status==='PENDING_CONFIRM'" class="btn secondary" @click="confirm(o.id)">人工确认</button></td></tr></tbody></table></div></template>
